		} else if (payload.action === 'suspend') {
			await this.githubInstallationModel.markSuspended({ installationId });
			this.logger.debug(`Installation ${installationId} suspended`);
		} else if (payload.action === 'unsuspend') {
			await this.githubInstallationModel.markActive({ installationId });
			this.logger.debug(`Installation ${installationId} unsuspended`);
		}
	}
}
